            >
            <div
              v-else-if="selectedOutput && selectedOutput.kind === 'video' && selectedOutput.url"
              class="output-preview__video"
              role="img"
              :aria-label="`视频预览 — ${selectedOutput.filename || '当前产出'}`"
            >
              <img :src="selectedOutput.url" :alt="''" class="output-preview__image">
