<script setup lang="ts">
import { computed, ref } from 'vue'

// ── Types (match existing OutputItem in ProjectWorkspacePage.vue) ────────────
//
// Scaffold uses the *same* local shapes the page already exposes. The coder is
// expected to forward the existing `OutputItem` / `OpenimagoProject` reactive
// refs into the matching props. New entities (Scene, Shot, Task, Approval) are
// deliberately NOT introduced — story elements are derived from existing data.

export interface ShotOutputItem {
  id: string
  url: string
  filename: string
  kind: 'image' | 'video' | 'audio'
  timeLabel: string
  promptText: string
  // Optional richer fields — only rendered when the page provides them
  model?: string | null
  resolution?: string | null
  durationLabel?: string | null
}

export type StoryElementKind = 'character' | 'scene' | 'prop' | 'reference'

export interface StoryElement {
  id: string
  title: string
  preview: string
  thumbnailUrl: string | null
  kind: StoryElementKind
  // Free-form sync state — page maps from real asset/workspace file sync.
  syncState?: 'synced' | 'pending' | 'error' | null
  timeLabel?: string
}

export type WorkspaceTabId =
  | 'overview'
  | 'storyboard'
  | 'timeline'
  | 'edit'
  | 'audio'
  | 'exports'

export type CenterTabId = 'prompt' | 'camera' | 'motion' | 'style' | 'negative'

export interface AssistantStatus {
  label: string
  tone: 'idle' | 'busy' | 'connected' | 'error'
}

export interface SessionCardItem {
  id: string
  title: string
  preview: string
  timeLabel: string
  clockLabel: string
  meta: string
  active: boolean
}

// ── Props ────────────────────────────────────────────────────────────────────

const props = withDefaults(
  defineProps<{
    projectName: string
    projectStatus: 'active' | 'archived'
    // Existing reactive data the page already owns
    outputs?: ShotOutputItem[]
    outputsLoading?: boolean
    selectedOutputId?: string | null
    storyElements?: StoryElement[]
    selectedElementId?: string | null
    sessionCount?: number | null
    outputCount?: number | null
    fileCount?: number
    // Optional right-panel wiring — page may pass; scaffold tolerates null
    hasSession?: boolean
    sessionLabel?: string | null
    isAssistantBusy?: boolean
    assistantStatus?: AssistantStatus | null
    // Optional credits / billing display
    creditsLabel?: string
    // Session list for left panel — primary navigation surface
    sessions?: SessionCardItem[]
    activeSessionId?: string | null
    isSessionSwitching?: boolean
  }>(),
  {
    outputs: () => [],
    outputsLoading: false,
    selectedOutputId: null,
    storyElements: () => [],
    selectedElementId: null,
    sessionCount: null,
    outputCount: null,
    fileCount: 0,
    hasSession: false,
    sessionLabel: null,
    isAssistantBusy: false,
    assistantStatus: null,
    creditsLabel: '—',
    sessions: () => [],
    activeSessionId: null,
    isSessionSwitching: false,
  },
)

const emit = defineEmits<{
  (e: 'back'): void
  (e: 'open-assets'): void
  (e: 'open-export'): void
  (e: 'workspace-tab-change', tab: WorkspaceTabId): void
  (e: 'output-select', id: string): void
  (e: 'element-select', id: string): void
  (e: 'add-element'): void
  (e: 'add-to-group', group: StoryElementKind): void
  (e: 'play-output', id: string): void
  (e: 'session-select', id: string): void
  (e: 'session-create'): void
}>()

// ── Local state (UI-only, no business logic) ─────────────────────────────────

const activeWorkspaceTab = ref<WorkspaceTabId>('storyboard')
const storyElementsExpanded = ref(false)

// ── Static tab definitions (table-driven to keep template tidy) ──────────────

interface TabDescriptor<TId extends string> {
  id: TId
  label: string
  icon?: string
}

const WORKSPACE_TABS: ReadonlyArray<TabDescriptor<WorkspaceTabId>> = [
  { id: 'overview', label: '概览' },
  { id: 'storyboard', label: '故事板' },
  { id: 'timeline', label: '时间线' },
  { id: 'edit', label: '剪辑' },
  { id: 'audio', label: '音频' },
  { id: 'exports', label: '导出记录' },
]

const STORY_ELEMENT_GROUPS: ReadonlyArray<{
  id: StoryElementKind
  label: string
  icon: string
}> = [
  { id: 'character', label: '角色', icon: 'person' },
  { id: 'scene', label: '场景', icon: 'landscape' },
  { id: 'prop', label: '道具', icon: 'category' },
  { id: 'reference', label: '参考图', icon: 'image' },
]

// ── Derived ──────────────────────────────────────────────────────────────────

const storyElementGroups = computed(() =>
  STORY_ELEMENT_GROUPS.map((group) => ({
    ...group,
    items: props.storyElements.filter((item) => item.kind === group.id),
  })),
)

const elementCount = computed(() => props.storyElements.length)

const selectedOutput = computed<ShotOutputItem | null>(
  () => props.outputs.find((item) => item.id === props.selectedOutputId) ?? null,
)

// ── Event handlers (named, not inline) ───────────────────────────────────────

function handleBack(): void {
  emit('back')
}

function handleOpenAssets(): void {
  emit('open-assets')
}

function handleOpenExport(): void {
  emit('open-export')
}

function handleWorkspaceTabSelect(tab: WorkspaceTabId): void {
  activeWorkspaceTab.value = tab
  emit('workspace-tab-change', tab)
}

function handleOutputSelect(id: string): void {
  emit('output-select', id)
}

function handleElementSelect(id: string): void {
  emit('element-select', id)
}

function handleAddElement(): void {
  emit('add-element')
}

function handleSessionSelect(id: string): void {
  emit('session-select', id)
}

function handleSessionCreate(): void {
  emit('session-create')
}

function handleAddToGroup(group: StoryElementKind): void {
  emit('add-to-group', group)
}

function handlePlaySelected(): void {
  if (props.selectedOutputId) emit('play-output', props.selectedOutputId)
}

function syncLabel(state: NonNullable<StoryElement['syncState']>): string {
  if (state === 'synced') return '已同步'
  if (state === 'pending') return '同步中'
  if (state === 'error') return '同步失败'
  return ''
}

function kindLabel(kind: ShotOutputItem['kind']): string {
  if (kind === 'image') return '图像'
  if (kind === 'video') return '视频'
  if (kind === 'audio') return '音频'
  return '文件'
}

// Expose for parent integration
defineExpose({
  setActiveWorkspaceTab: (tab: WorkspaceTabId) => {
    activeWorkspaceTab.value = tab
  },
})
</script>

<style lang="scss" scoped>
// ── Design tokens — read from the global imago system, never hardcode colors ─
//
// This scaffold does NOT introduce new color values. Every background, border,
// and accent is sourced from the existing --imago-* tokens defined in
// /packages/web/src/css/app.scss.

.project-workspace-grid {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  min-height: 100%;
  background: var(--imago-bg-void);
  color: var(--imago-text-primary);
  isolation: isolate; // keep the ambient orbs behind the grid
}

// ── Ambient backdrop ─────────────────────────────────────────────────────
.grid-ambient {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  overflow: hidden;
}

.grid-ambient__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.35;
  animation: orb-drift 20s ease-in-out infinite;
}

.grid-ambient__orb--cyan {
  top: -80px;
  left: 18%;
  width: 380px;
  height: 380px;
  background: radial-gradient(circle, rgba(0, 240, 255, 0.10), transparent 65%);
}

.grid-ambient__orb--violet {
  top: 30%;
  right: -80px;
  width: 320px;
  height: 320px;
  background: radial-gradient(circle, rgba(168, 85, 247, 0.08), transparent 65%);
  animation-delay: -8s;
  animation-duration: 24s;
}

.grid-ambient__ambient-grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(0, 240, 255, 0.020) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 240, 255, 0.020) 1px, transparent 1px);
  background-size: 56px 56px;
  background-position: -1px -1px;
  mask-image: radial-gradient(ellipse 80% 60% at 50% 0%, black 30%, transparent 80%);
  -webkit-mask-image: radial-gradient(ellipse 80% 60% at 50% 0%, black 30%, transparent 80%);
}

@keyframes orb-drift {
  0%, 100% { transform: translate3d(0, 0, 0) scale(1); }
  33%      { transform: translate3d(40px, -20px, 0) scale(1.08); }
  66%      { transform: translate3d(-30px, 30px, 0) scale(0.95); }
}

@media (prefers-reduced-motion: reduce) {
  .grid-ambient__orb { animation: none !important; }
}

// ── Command bar ───────────────────────────────────────────────────────────
.command-bar {
  position: relative;
  z-index: 2;
  display: flex;
  align-items: center;
  gap: 16px;
  height: 60px;
  flex-shrink: 0;
  padding: 0 20px;
  border-bottom: 1px solid var(--imago-border-light);
  background: linear-gradient(180deg, rgba(8, 8, 15, 0.92), rgba(8, 8, 15, 0.78));
  backdrop-filter: var(--imago-blur-panel);
  -webkit-backdrop-filter: var(--imago-blur-panel);
}

.command-bar__left {
  display: flex;
  align-items: center;
  gap: 14px;
  min-width: 0;
  flex: 0 0 auto;
}

.command-bar__back {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border: 1px solid var(--imago-border-light);
  border-radius: var(--imago-radius-md);
  background: transparent;
  color: var(--imago-text-muted);
  cursor: pointer;
  transition: color var(--imago-ease-fast), background var(--imago-ease-fast),
    border-color var(--imago-ease-fast);

  &:hover {
    color: var(--imago-text-primary);
    background: var(--imago-bg-raised);
    border-color: var(--imago-border-soft);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.command-bar__title-block {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.command-bar__title {
  margin: 0;
  font-size: 16px;
  font-weight: 600;
  color: var(--imago-text-primary);
  letter-spacing: -0.005em;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.command-bar__meta {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11.5px;
  color: var(--imago-text-dim);
}

.command-bar__status {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 1px 8px;
  border-radius: var(--imago-radius-pill);
  font-size: 11px;
  font-weight: 500;
  background: var(--imago-cyan-08);
  color: rgba(0, 240, 255, 0.82);
  border: 1px solid var(--imago-border-cyan);
}

.command-bar__status--archived {
  background: var(--imago-bg-raised);
  color: var(--imago-text-dim);
  border-color: var(--imago-border-light);
}

.command-bar__status-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--imago-neon-cyan);
  box-shadow: 0 0 6px var(--imago-cyan-08);
}

.command-bar__status--archived .command-bar__status-dot {
  background: var(--imago-text-faint);
  box-shadow: none;
}

.command-bar__meta-divider {
  color: var(--imago-text-faint);
}

.command-bar__meta-text {
  color: var(--imago-text-secondary);
  font-weight: 500;
}

// Tabs — segmented control
.command-bar__tabs {
  display: flex;
  align-items: center;
  gap: 2px;
  flex: 1 1 auto;
  min-width: 0;
  padding: 4px;
  border: 1px solid var(--imago-border-light);
  border-radius: var(--imago-radius-lg);
  background: var(--imago-bg-deep);
  overflow-x: auto;
  scrollbar-width: none;

  &::-webkit-scrollbar { display: none; }
}

.command-bar__tab {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
  padding: 6px 12px;
  border: 1px solid transparent;
  border-radius: var(--imago-radius-md);
  background: transparent;
  color: var(--imago-text-muted);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: color var(--imago-ease-fast), background var(--imago-ease-fast),
    border-color var(--imago-ease-fast);

  &:hover {
    color: var(--imago-text-primary);
    background: var(--imago-bg-raised);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.command-bar__tab--active {
  color: var(--imago-neon-cyan);
  background: var(--imago-cyan-06);
  border-color: var(--imago-border-cyan-active);
  box-shadow: var(--imago-glow-cyan-inline);
}

.command-bar__tab-icon {
  opacity: 0.75;
}

.command-bar__right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 0 0 auto;
}

.command-bar__action {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  border: 1px solid var(--imago-border-light);
  border-radius: var(--imago-radius-md);
  background: var(--imago-bg-raised);
  color: var(--imago-text-secondary);
  font-size: 12.5px;
  font-weight: 500;
  cursor: pointer;
  transition: color var(--imago-ease-fast), background var(--imago-ease-fast),
    border-color var(--imago-ease-fast);

  &:hover {
    color: var(--imago-text-primary);
    border-color: var(--imago-border-cyan);
    background: var(--imago-cyan-04);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.command-bar__credits {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 5px 10px;
  border: 1px solid var(--imago-border-cyan);
  border-radius: var(--imago-radius-md);
  background: var(--imago-cyan-04);
  color: var(--imago-neon-cyan);
  font-size: 12px;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

.command-bar__credits-icon { opacity: 0.85; }

// ── Three-column grid body ──────────────────────────────────────────────────
.grid-body {
  position: relative;
  z-index: 1;
  display: grid;
  grid-template-columns: 280px minmax(0, 1fr) 320px;
  gap: 0;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

@media (max-width: 1280px) {
  .grid-body {
    grid-template-columns: 240px minmax(0, 1fr) 280px;
  }
}

@media (max-width: 1024px) {
  .grid-body {
    grid-template-columns: 220px minmax(0, 1fr);
  }
  .grid-column--right {
    display: none;
  }
}

@media (max-width: 768px) {
  .grid-body {
    grid-template-columns: 1fr;
  }
  .grid-column--left {
    display: none;
  }
}

.grid-column {
  position: relative;
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

.grid-column--left {
  border-right: 1px solid var(--imago-border-light);
  background: linear-gradient(180deg, var(--imago-bg-deep), var(--imago-bg-void) 40%);
}

.grid-column--center {
  background: var(--imago-bg-void);
}

.grid-column--right {
  border-left: 1px solid var(--imago-border-light);
  background: linear-gradient(180deg, var(--imago-bg-deep), var(--imago-bg-void) 40%);
}

.grid-column__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  padding: 18px 18px 12px;
  flex-shrink: 0;
}

.grid-column__title-block {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.grid-column__title {
  margin: 0;
  font-size: 14px;
  font-weight: 600;
  color: var(--imago-text-primary);
  letter-spacing: 0.005em;
}

.grid-column__subtitle {
  margin: 0;
  font-size: 11.5px;
  color: var(--imago-text-dim);
  line-height: 1.4;
}

.grid-column__add {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border: 1px solid var(--imago-border-soft);
  border-radius: var(--imago-radius-md);
  background: var(--imago-bg-raised);
  color: var(--imago-text-muted);
  cursor: pointer;
  transition: color var(--imago-ease-fast), background var(--imago-ease-fast),
    border-color var(--imago-ease-fast);

  &:hover {
    color: var(--imago-neon-cyan);
    background: var(--imago-cyan-06);
    border-color: var(--imago-border-cyan-active);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.grid-column__status {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 2px 8px;
  border-radius: var(--imago-radius-pill);
  font-size: 10.5px;
  font-weight: 500;
  background: var(--imago-bg-raised);
  color: var(--imago-text-dim);
  border: 1px solid var(--imago-border-light);
}

.grid-column__status-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--imago-text-faint);
}

.grid-column__status--idle .grid-column__status-dot { background: var(--imago-text-faint); }
.grid-column__status--connected {
  color: rgba(0, 240, 255, 0.82);
  border-color: var(--imago-border-cyan);
  background: var(--imago-cyan-06);
}
.grid-column__status--connected .grid-column__status-dot {
  background: var(--imago-neon-cyan);
  box-shadow: 0 0 6px var(--imago-cyan-08);
}
.grid-column__status--busy {
  color: rgba(168, 85, 247, 0.88);
  border-color: rgba(168, 85, 247, 0.24);
  background: rgba(168, 85, 247, 0.06);
}
.grid-column__status--busy .grid-column__status-dot {
  background: var(--imago-neon-purple);
  box-shadow: 0 0 6px rgba(168, 85, 247, 0.30);
}
.grid-column__status--error {
  color: #fda4af;
  border-color: rgba(244, 63, 94, 0.30);
  background: rgba(244, 63, 94, 0.06);
}
.grid-column__status--error .grid-column__status-dot {
  background: #f43f5e;
}

// ── LEFT: Session list (primary) ──────────────────────────────────────────────
.session-list-panel {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  padding: 4px 12px 8px 16px;
}

.session-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.session-group__title {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 0 2px;
  position: sticky;
  top: 0;
  z-index: 1;
  background: linear-gradient(180deg, var(--imago-bg-deep), transparent);
  font-size: 10.5px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--imago-text-dim);
}

.session-group__count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 16px;
  padding: 0 5px;
  border-radius: var(--imago-radius-pill);
  font-size: 10px;
  font-weight: 600;
  color: var(--imago-neon-cyan);
  background: var(--imago-cyan-06);
  border: 1px solid var(--imago-border-cyan);
  font-variant-numeric: tabular-nums;
}

.session-list {
  display: grid;
  gap: 8px;
}

.session-list-empty {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px;
  border: 1px dashed var(--imago-border-soft);
  border-radius: var(--imago-radius-md);
  color: var(--imago-text-faint);
  font-size: 11.5px;
  text-align: center;
  justify-content: center;
}

.session-card {
  display: flex;
  flex-direction: column;
  padding: 12px;
  border: 1px solid var(--imago-border-light);
  border-radius: var(--imago-radius-md);
  background: var(--imago-bg-surface);
  text-align: left;
  cursor: pointer;
  transition: border-color var(--imago-ease-default), background var(--imago-ease-default),
    box-shadow var(--imago-ease-default), transform var(--imago-ease-default);

  &:hover {
    border-color: var(--imago-border-cyan);
    background: var(--imago-bg-raised);
    transform: translateY(-1px);
    box-shadow: 0 0 26px rgba(0, 240, 255, 0.06);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.session-card--active {
  border-color: var(--imago-border-cyan-active);
  background: var(--imago-cyan-04);
  box-shadow: inset 0 0 0 1px var(--imago-border-cyan),
    0 0 34px rgba(0, 240, 255, 0.1);
}

.session-card__body {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.session-card__row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 8px;
}

.session-card__title {
  font-size: 13px;
  font-weight: 500;
  color: var(--imago-text-primary);
  line-height: 1.3;
}

.session-card__time {
  flex-shrink: 0;
  font-size: 11px;
  color: var(--imago-text-faint);
  white-space: nowrap;
}

.session-card__preview {
  font-size: 12px;
  color: var(--imago-text-dim);
  line-height: 1.45;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.session-card__meta {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 10.5px;
  color: var(--imago-text-faint);
}

.session-card__meta-label {
  color: var(--imago-text-muted);
  font-weight: 500;
}

.session-card__meta-time {
  color: var(--imago-text-faint);
  font-variant-numeric: tabular-nums;
}

// ── LEFT: Story elements (secondary, collapsed by default) ────────────────────
.elements-section {
  flex-shrink: 0;
  border-top: 1px solid var(--imago-border-light);
}

.elements-section__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 12px 16px 4px;
}

.elements-section__toggle {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 0;
  border: 0;
  background: transparent;
  color: inherit;
  cursor: pointer;
  flex: 1;
  min-width: 0;
  text-align: left;

  &:hover .elements-section__toggle-icon {
    color: var(--imago-neon-cyan);
  }
}

.elements-section__toggle-icon {
  color: var(--imago-text-muted);
  transition: color var(--imago-ease-fast);
}

// ── LEFT: Story elements (unchanged visual styling) ───────────────────────────
.elements-list {
  max-height: 320px;
  overflow-y: auto;
  padding: 4px 12px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.element-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.element-group__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 0 2px;
  position: sticky;
  top: 0;
  background: linear-gradient(180deg, var(--imago-bg-deep), transparent);
  z-index: 1;
}

.element-group__label-block {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.element-group__label {
  font-size: 10.5px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--imago-text-dim);
}

.element-group__count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 16px;
  padding: 0 5px;
  border-radius: var(--imago-radius-pill);
  font-size: 10px;
  font-weight: 600;
  color: var(--imago-text-muted);
  background: var(--imago-bg-raised);
  border: 1px solid var(--imago-border-light);
  font-variant-numeric: tabular-nums;
}

.element-group__add {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  padding: 0;
  border: 1px solid transparent;
  border-radius: var(--imago-radius-sm);
  background: transparent;
  color: var(--imago-text-muted);
  cursor: pointer;
  transition: color var(--imago-ease-fast), background var(--imago-ease-fast),
    border-color var(--imago-ease-fast);

  &:hover {
    color: var(--imago-neon-cyan);
    background: var(--imago-cyan-06);
    border-color: var(--imago-border-cyan);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.element-group__items {
  display: grid;
  grid-template-columns: 1fr;
  gap: 8px;
}

.element-group__empty {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  border: 1px dashed var(--imago-border-soft);
  border-radius: var(--imago-radius-md);
  color: var(--imago-text-faint);
  font-size: 11.5px;
}

.element-card {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 6px;
  border: 1px solid var(--imago-border-light);
  border-radius: var(--imago-radius-md);
  background: var(--imago-bg-surface);
  text-align: left;
  cursor: pointer;
  transition: border-color var(--imago-ease-default), box-shadow var(--imago-ease-default),
    background var(--imago-ease-default);

  &:hover {
    border-color: var(--imago-border-cyan);
    background: var(--imago-bg-raised);
  }

  &:focus-visible {
    outline: 2px solid var(--imago-neon-cyan);
    outline-offset: 2px;
  }
}

.element-card--active {
  border-color: var(--imago-border-cyan-active);
  background: var(--imago-cyan-04);
  box-shadow: inset 0 0 0 1px var(--imago-border-cyan),
    0 0 16px rgba(0, 240, 255, 0.06);
}

.element-card__thumb {
  position: relative;
  aspect-ratio: 16 / 10;
  overflow: hidden;
  border-radius: var(--imago-radius-sm);
  background: var(--imago-bg-code);
  border: 1px solid var(--imago-border-subtle);
}

.element-card__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.element-card__thumb-fallback {
  width: 100%;
  height: 100%;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, var(--imago-bg-deep), var(--imago-bg-panel));
}

.element-card__sync {
  position: absolute;
  top: 6px;
  right: 6px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: var(--imago-bg-deep);
  border: 1px solid var(--imago-border-soft);
  display: grid;
  place-items: center;
}

.element-card__sync-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--imago-text-faint);
}

.element-card__sync--synced {
  border-color: var(--imago-border-cyan);
  background: var(--imago-cyan-06);
}
.element-card__sync--synced .element-card__sync-dot {
  background: var(--imago-neon-cyan);
  box-shadow: 0 0 4px var(--imago-cyan-08);
}

.element-card__sync--pending {
  border-color: rgba(168, 85, 247, 0.24);
  background: rgba(168, 85, 247, 0.06);
}
.element-card__sync--pending .element-card__sync-dot {
  background: var(--imago-neon-purple);
  animation: sync-pulse 1.4s ease-in-out infinite;
}

.element-card__sync--error {
  border-color: rgba(244, 63, 94, 0.30);
  background: rgba(244, 63, 94, 0.08);
}
.element-card__sync--error .element-card__sync-dot { background: #f43f5e; }

@keyframes sync-pulse {
  0%, 100% { opacity: 0.4; transform: scale(0.85); }
  50%      { opacity: 1.0; transform: scale(1.15); }
}

@media (prefers-reduced-motion: reduce) {
  .element-card__sync--pending .element-card__sync-dot { animation: none; }
}

.element-card__body {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 0 2px 2px;
}

